import (
    "context"
    "github.com/anthropics/anthropic-sdk-go"
)

client := anthropic.NewClient()

message, err := client.Messages.Create(context.Background(), anthropic.MessageCreateParams{
    Model:      anthropic.ModelClaudeOpus4_8,
    MaxTokens:  1024,
    Messages: []anthropic.MessageParam{
        anthropic.UserMessage("Hello, Claude"),
    },
})

fmt.Println(message.Content)

stream, err := client.Messages.CreateStream(context.Background(), anthropic.MessageCreateParams{
    Model:      anthropic.ModelClaudeOpus4_8,
    MaxTokens:  1024,
    Messages: []anthropic.MessageParam{
        anthropic.UserMessage("Hello, Claude"),
    },
})

for iter := stream; iter.Next(context.Background()); {
    event := iter.Value()
    fmt.Println(event.Type)  // "message_start", "content_block_delta", ...
}

using Anthropic.Client;

var client = new AnthropicClient(new AnthropicCredentials(
