));

var message = await client.Messages.CreateAsync(new MessageCreationParams
{
    Model = Model.ClaudeOpus4_8,
    MaxTokens = 1024,
    Messages = new[] { new MessageParam("user", "Hello, Claude") }
});

Console.WriteLine(message.Content[0].Text);

var chatClient = client.GetChatClient(Model.ClaudeOpus4_8);
